     * - Falls back to og:title/twitter:title/h1 if &lt;title&gt; is missing
     * - Provides a URL-based fallback if the page is not HTML or no title is found
     */
    public String fetchTitleFromUrl(String urlString) throws IOException {
        if (urlString == null || urlString.isBlank()) {
            throw new IllegalArgumentException("URL must not be null or blank");
        }

        URL url = new URL(urlString);
        String protocol = url.getProtocol();
        if (!"http".equalsIgnoreCase(protocol) && !"https".equalsIgnoreCase(protocol)) {
            throw new IOException("Unsupported protocol: " + protocol);
        }

        Connection connection = Jsoup
                .connect(url.toString())
                .userAgent(DEFAULT_USER_AGENT)
                .referrer("https://www.google.com/")
                .timeout(DEFAULT_TIMEOUT_MS)
                .followRedirects(true)
                .maxBodySize(MAX_BODY_SIZE_BYTES)
                .ignoreHttpErrors(true) // capture status for explicit handling
                .header("Accept-Language", "zh-CN,zh;q=0.9,en;q=0.8")
                .header("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8");

        Connection.Response response = connection.execute();

        int status = response.statusCode();
        if (status >= 400) {
            throw new IOException("HTTP error fetching URL (" + status + "): " + url);
        }

        String contentType = response.contentType();
        if (contentType != null && !contentType.toLowerCase(Locale.ROOT).contains("html")) {
            // Not HTML; fall back to deriving a reasonable label from the URL
            return fallbackTitleFromUrl(url);
        }

        Document doc = response.parse();

        String title = extractTitle(doc);
        if (title == null || title.isBlank()) {
            title = fallbackTitleFromUrl(url);
        }

        return title;
    }

