        // Prefer the <title> tag
        String title = clean(doc.title());
        if (!title.isBlank()) {
            return title;
        }

        // Try common metadata fallbacks
        Element og = doc.selectFirst("meta[property=og:title][content]");
        if (og != null) {
            title = clean(og.attr("content"));
            if (!title.isBlank()) return title;
        }

        Element twitter = doc.selectFirst("meta[name=twitter:title][content]");
        if (twitter != null) {
            title = clean(twitter.attr("content"));
            if (!title.isBlank()) return title;
        }

        Element metaTitle = doc.selectFirst("meta[name=title][content]");
        if (metaTitle != null) {
            title = clean(metaTitle.attr("content"));
            if (!title.isBlank()) return title;
        }

        // Last resort: first H1
        Element h1 = doc.selectFirst("h1");
        if (h1 != null) {
            title = clean(h1.text());
            if (!title.isBlank()) return title;
        }

        return null;
    }

    private String fallbackTitleFromUrl(URL url) {
        String candidate = null;

        String path = url.getPath();
        if (path != null && !path.isBlank() && !"/".equals(path)) {
            String[] segments = path.split("/");
            for (int i = segments.length - 1; i >= 0; i--) {
                if (!segments[i].isBlank()) {
                    candidate = segments[i];
                    break;
                }
            }
            if (candidate != null) {
                candidate = urlDecode(candidate);
                candidate = candidate.replace('-', ' ').replace('_', ' ');
            }
        }

        if (candidate == null || candidate.isBlank()) {
            candidate = url.getHost();
        }

        return clean(candidate);
    }

    private String clean(String s) {
        if (s == null) return "";
        // Normalize whitespace
        String t = WHITESPACE.matcher(s).replaceAll(" ").trim();
        // Remove trivial separators at ends
        t = trimTrailingSeparators(t);
        if (t.length() > MAX_TITLE_LENGTH) {
            t = t.substring(0, MAX_TITLE_LENGTH).trim();
        }
        return t;
    }

    private String trimTrailingSeparators(String s) {
        String t = s;
        // Remove leading/trailing separator tokens commonly used in titles
        while (true) {
            String original = t;
            t = t.replaceAll("^(?:" + TRAILING_SITE_SEP.pattern() + ")+", "");
            t = t.replaceAll("(?:" + TRAILING_SITE_SEP.pattern() + ")+$", "");
            if (t.equals(original)) break;
        }
        return t;
    }

    private String urlDecode(String value) {
        try {
            return URLDecoder.decode(value, StandardCharsets.UTF_8);
        } catch (IllegalArgumentException ex) {
            // Malformed percent-encoding; return as-is
            return value;
        }
    }
}

