    private static final int CONNECT_TIMEOUT_MS = 5000;
    private static final int READ_TIMEOUT_MS = 5000;
    private static final int MAX_REDIRECTS = 5;
    private static final long MAX_BYTES = 1_000_000; // 1 MB cap

    public String fetchTitleFromUrl(String urlString) throws IOException {
        URI currentUri = toSafeUri(urlString);

        for (int redirectCount = 0; redirectCount <= MAX_REDIRECTS; redirectCount++) {
            validateScheme(currentUri);
            validateNoUserInfo(currentUri);
            validatePublicResolvableHost(currentUri);

            URL url = currentUri.toURL();
            HttpURLConnection conn = (HttpURLConnection) url.openConnection(Proxy.NO_PROXY);
            conn.setInstanceFollowRedirects(false); // we manage redirects manually
            conn.setConnectTimeout(CONNECT_TIMEOUT_MS);
            conn.setReadTimeout(READ_TIMEOUT_MS);
            conn.setRequestMethod("GET");
            conn.setRequestProperty("User-Agent", "BookmarkService/1.0 (+https://example.com)");
            conn.setRequestProperty("Accept", "text/html,application/xhtml+xml");
            conn.setRequestProperty("Connection", "close");

            try {
                int status = conn.getResponseCode();

                if (isRedirect(status)) {
                    String location = conn.getHeaderField("Location");
                    if (location == null || location.isEmpty()) {
                        throw new IOException("Redirect without Location header");
                    }
                    // Resolve relative redirects against the current URI
                    URI next = resolveRedirect(currentUri, location);

                    // Validate the redirect target before following it
                    validateScheme(next);
                    validateNoUserInfo(next);
                    validatePublicResolvableHost(next);

                    // Proceed to next hop
                    currentUri = next;
                    // Close any open streams
                    safeDisconnect(conn);
                    continue;
                }

                if (status == HttpURLConnection.HTTP_OK) {
                    // Optional: ensure content type looks like HTML
                    String contentType = conn.getHeaderField("Content-Type");
                    if (contentType != null && !contentType.toLowerCase().contains("html")) {
                        throw new IOException("Unsupported content type: " + contentType);
                    }

                    // Enforce size limit using Content-Length when available
                    long contentLength = parseContentLength(conn.getHeaderField("Content-Length"));
                    if (contentLength > MAX_BYTES) {
                        throw new IOException("Content too large (" + contentLength + " bytes)");
                    }

                    try (InputStream raw = new BufferedInputStream(conn.getInputStream());
                         InputStream limited = new LimitInputStream(raw, MAX_BYTES)) {
                        // Let jsoup detect charset (pass null)
                        Document doc = Jsoup.parse(limited, null, currentUri.toString());
                        String title = doc.title();
                        return title == null ? "" : title.trim();
                    } finally {
                        safeDisconnect(conn);
                    }
                }

                throw new IOException("Unexpected HTTP status: " + status);
            } catch (IOException e) {
                safeDisconnect(conn);
                throw e;
            }
        }

        throw new IOException("Too many redirects");
