    private static URI toSafeUri(String urlString) throws IOException {
        try {
            // Normalize via URI to catch invalid forms
            URI uri = new URI(urlString.trim());
            if (uri.getHost() == null) {
                // Try to force parsing by adding // if missing
                // or re-parse via URL then to URI
