        if (header == null) return -1;
        try {
            return Long.parseLong(header.trim());
        } catch (NumberFormatException e) {
            return -1;
        }
    }

    private static void safeDisconnect(HttpURLConnection conn) {
        try {
            if (conn != null) {
                // Ensure input stream is closed to let the connection release resources
                try {
                    InputStream is = conn.getInputStream();
                    if (is != null) is.close();
                } catch (IOException ignored) {
                }
                try {
                    InputStream es = conn.getErrorStream();
                    if (es != null) es.close();
                } catch (IOException ignored) {
                }
                conn.disconnect();
            }
        } catch (Exception ignored) {
        }
    }

    /**
     * InputStream wrapper that enforces a maximum number of bytes read.
     */
    private static final class LimitInputStream extends FilterInputStream {
        private long remaining;

        protected LimitInputStream(InputStream in, long maxBytes) {
            super(in);
            if (maxBytes < 0) throw new IllegalArgumentException("maxBytes must be >= 0");
            this.remaining = maxBytes;
        }

        @Override
        public int read() throws IOException {
            if (remaining <= 0) return -1;
            int r = super.read();
            if (r != -1) remaining--;
            return r;
        }

        @Override
        public int read(byte[] b, int off, int len) throws IOException {
            if (remaining <= 0) return -1;
            int toRead = (int) Math.min(len, remaining);
            int r = super.read(b, off, toRead);
            if (r != -1) remaining -= r;
            return r;
        }

        @Override
        public long skip(long n) throws IOException {
            long toSkip = Math.min(n, remaining);
            long skipped = super.skip(toSkip);
            remaining -= skipped;
            return skipped;
        }
    }
}

