            // 192.0.0.0/24
            if (inRange(ip, 0xC0000000, 24)) return true;
            // 192.0.2.0/24 (TEST-NET-1)
            if (inRange(ip, 0xC0000200, 24)) return true;
            // 192.168.0.0/16
            if (inRange(ip, 0xC0A80000, 16)) return true;
            // 198.18.0.0/15 (benchmark)
            if (inRange(ip, 0xC6120000, 15)) return true;
            // 198.51.100.0/24 (TEST-NET-2)
            if (inRange(ip, 0xC6336400, 24)) return true;
            // 203.0.113.0/24 (TEST-NET-3)
            if (inRange(ip, 0xCB007100, 24)) return true;
            // 224.0.0.0/4 (multicast and reserved)
            if (inRange(ip, 0xE0000000, 4)) return true;
            // 240.0.0.0/4 (reserved)
            if (inRange(ip, 0xF0000000, 4)) return true;
        }

        return false;
    }

